/**
 * @brief     This function is used to set full screen for displaying image on LCD.
 *
 * @param[in]  NA
 *
 * @return     NA
 *
 * Reference : 1) Working with STM32F4 and SPI-TFT: ST7789 IPS 240×240 LCD by Husamuldeen
 *             https://blog.embeddedexpert.io/?p=1215
 *             2) Github Repository : Majid Derhambakhsh
 *             https://github.com/Majid-Derhambakhsh/ST7789/blob/main/Src/st7789.c
 *
 * Original Author: Majid Derhambakhsh (Github Repository) and Husamuldeen (Embedded Expert IO blog)
 *
 * Modified by: Likhita Jonnakuti
 *
 */
void ST7789_SetFullScreen(void)
{
    writecommand(0x2A);     // CASET
    writedata(0x00);
    writedata(0x00);
    writedata((IMG_WIDTH - 1) >> 8);
    writedata((IMG_WIDTH - 1) & 0xFF);

    writecommand(0x2B);     // RASET
    writedata(0x00);
    writedata(0x00);
    writedata((IMG_HEIGHT - 1) >> 8);
    writedata((IMG_HEIGHT - 1) & 0xFF);
    writecommand(0x2C);     // RAMWR
}
/**
 * @brief     This function is used to draw full screen
 *
 * @param[in]  NA
 *
 * @return     NA
 *
 * Reference : 1) Working with STM32F4 and SPI-TFT: ST7789 IPS 240×240 LCD by Husamuldeen
 *             https://blog.embeddedexpert.io/?p=1215
 *             2) Github Repository : Majid Derhambakhsh
 *             https://github.com/Majid-Derhambakhsh/ST7789/blob/main/Src/st7789.c
 *
 * Original Author: Majid Derhambakhsh (Github Repository) and Husamuldeen (Embedded Expert IO blog)
 *
 * Modified by: Likhita Jonnakuti
 *
 */
void ST7789_DrawFullScreen(const uint16_t *img)
{
    ST7789_SetFullScreen();

    DC_DATA();
    CS_LOW();

    for (uint32_t i = 0; i < (45*50); i++)
    {
        uint16_t c = img[i];
        spi1_write(c >> 8);
        spi1_write(c & 0xFF);
    }

    CS_HIGH();
}
